from collections import namedtuple

import pytest
from Bio import pairwise2

from chemutils.protein.alignment import SequenceAlignment

Case = namedtuple("Point", "sequence reference aligned_sequence aligned_reference nomenclature")


CASES = [
    # 7RPZ (KRAS)
    Case(
        sequence="GMTEYKLVVVGADGVGKSALTIQLIQNHFVDEYDPTIEDSYRKQVVIDGETSLLDILDTAGQEEYSAMRDQYMRTGEGFLLVFAINNTKSFEDIHHYREQIKRVKDSEDVPMVLVGNKSDLPSRTVDTKQAQDLARSYGIPFIETSAKTRQGVDDAFYTLVREIRKHKEK",
        reference="MTEYKLVVVGAGGVGKSALTIQLIQNHFVDEYDPTIEDSYRKQVVIDGETCLLDILDTAGQEEYSAMRDQYMRTGEGFLCVFAINNTKSFEDIHHYREQIKRVKDSEDVPMVLVGNKCDLPSRTVDTKQAQDLARSYGIPFIETSAKTRQGVDDAFYTLVREIRKHKEKMSKDGKKKKKKSKTKCVIM",
        aligned_sequence="GMTEYKLVVVGADGVGKSALTIQLIQNHFVDEYDPTIEDSYRKQVVIDGETSLLDILDTAGQEEYSAMRDQYMRTGEGFLLVFAINNTKSFEDIHHYREQIKRVKDSEDVPMVLVGNKSDLPSRTVDTKQAQDLARSYGIPFIETSAKTRQGVDDAFYTLVREIRKHKEK-------------------",
        aligned_reference="-MTEYKLVVVGAGGVGKSALTIQLIQNHFVDEYDPTIEDSYRKQVVIDGETCLLDILDTAGQEEYSAMRDQYMRTGEGFLCVFAINNTKSFEDIHHYREQIKRVKDSEDVPMVLVGNKCDLPSRTVDTKQAQDLARSYGIPFIETSAKTRQGVDDAFYTLVREIRKHKEKMSKDGKKKKKKSKTKCVIM",
        nomenclature="_M1insG G12D C51S C80L C118S M170_M188del",
    ),
    # 7UJ4 (MEN1)
    Case(
        sequence="",
        reference="",
        aligned_sequence="MGLKTAQKTLFPLRSIDDVVRLFAAELGREEPDLVLLSLVLGFVEHFLAVNRVIPTNVPELTFQPSPAPDPPGGLTYFPVADLSIIAALYARFTAQIRGAVDLSLYPREGGVSSRELVKKVSDVIWNSLSRSYFKDRAHIQSLFSFIT---------------------------------------------------------------------------------------------------TFQSEKMKGMKELLVATKINSSAIKLQLTAQ----------------------------",
        aligned_reference="",
        nomenclature="A5T G149_V153del V463_L556del S588_L615del",
    ),
]


@pytest.mark.parametrize(
    ["sequence", "reference", "aligned_sequence", "aligned_reference", "nomenclature"], CASES
)
def test_sequence_alignment_from_biopython_globalxx(
    sequence, reference, aligned_sequence, aligned_reference, nomenclature
):
    match_score = 5
    mismatch_score = -2
    open_gap_score = -4
    extended_gap_score = -1
    biopython_alignment = pairwise2.align.localms(
        sequence, reference, match_score, mismatch_score, open_gap_score, extended_gap_score
    )[0]
    alignment = SequenceAlignment.from_biopython(biopython_alignment)
    assert alignment.sequence == sequence
    assert alignment.reference == reference
    assert alignment.aligned_sequence == aligned_sequence
    assert alignment.aligned_reference == aligned_reference
    assert alignment.nomenclature == nomenclature
